INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893bf","title":"Капитан Америка. Зимний Солдат","author":"Эд Брубейкер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002072048/140/ab07/Ed_Brubejker__Kapitan_Amerika._Zimnij_Soldat.jpg","isbn":"978-5-91878-174-6","publisher":"Фантастика Книжный Клуб","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Более пятидесяти лет Советы использовали для ликвидации западных политиков тайного агента — непобедимого, не оставляющего следов убийцу, известного как Зимний Солдат. Кто же скрывается под этим именем? Баки Барнс — бывший напарник Капитана Америка, якобы погибший в последние дни Второй мировой войны. Теперь Зимний Солдат вернулся и работает под руководством безжалостного генерала Лукина, заполучившего космический куб — оружие безграничной силы, способное изменять саму реальность. Поклявшись покончить с террором и разрушениями, которые сеет Лукин, Капитан Америка неотступно движется по следу куба, но в итоге сталкивается лицом к лицу с Зимним Солдатом. Неужели Кэпу придётся сразиться с вернувшимся к жизни напарником, после того как он наконец узнал страшную правду? Наполнив каждую страницу шокирующими откровениями, пятикратный номинант на премию Айснера Эд Брубейкер рассказывает напряжённую и интригующую историю, поразившую как критиков, так и фанатов. Ain’t It Cool News назвал её «одной из самых лучших и грандиозных историй о Капитане Америка всех времён».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-03","rating":3,"review":"","added":9999295,"hdCover":""},{"id":"09893be","title":"Ходячие мертвецы. Полное собрание. Том 4.","author":"Роберт Киркман,Клифф Ратбёрн,Стефано Гаудиано,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003901488/140/bdeb/__Hodyachie_mertvetsy._Polnoe_sobranie._Tom_4..jpg","isbn":"978-5-04-107468-5","publisher":"Комильфо","pubDate":"2019","language":"","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-03","rating":5,"review":"","added":9999294,"hdCover":""},{"id":"09893bd","title":"Ходячие мертвецы. А вот и Ниган!","author":"Роберт Киркман","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004569783/140/997c/Robert_Kirkman__Hodyachie_mertvetsy._A_vot_i_Nigan.jpg","isbn":"978-5-04-114197-4","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Ниган, появившийся в сотом выпуске «Ходячих мертвецов», моментально стал архиврагом Рика Граймса… и одним из самых любимых персонажей читателей комикса! Как так получилось? Всему виной термоядерная смесь из невероятной харизмы, отменного чёрного юмора, склонности к ультранасилию и глубоко скрытой личной трагедии сделали Нигана культовым персонажем. Как он стал кровавым диктатором? Почему он так привязан к своей бите и почему её зовут Люсиль? Кем был Ниган до конца света. Читатели основной серии комиксов так и остались без должных ответов на эти вопросы. Но тут всем фанатам харизматичного мерзавца приходит на помощь эта мини-серия! Под обложкой спрятано всё, что вы хотели знать о прошлом Нигана!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-03","rating":3.5,"review":"","added":9999293,"hdCover":""},{"id":"09893bc","title":"Ходячие мертвецы. Полное собрание. Том 3","author":"Роберт Киркман,Клифф Ратбёрн,Стефано Гаудиано,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002946150/140/d4d7/__Hodyachie_mertvetsy._Polnoe_sobranie._Tom_3.jpg","isbn":"978-5-91339-712-6","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"Сколько часов в день вы не тратите, просиживая перед телевизором? Когда в последний раз кто-нибудь из нас на самом деле старался, чтобы получить желаемое? Давно ли кто-то из нас действительно нуждался в том, что постоянно хочет?  Мир, который мы знали, исчез.  На смену миру торговли и пустого потребительства пришёл мир выживания и ответственности.  Эпидемия апокалиптических масштабов прокатилась по планете, пробудив мёртвых, которые начали пожирать живых. За несколько месяцев человеческое общество было разрушено. Исчезли правительства, магазины, доставка почты, кабельное телевидение.  В мире, где правят мёртвые, мы наконец вынуждены начать жить.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-03","rating":5,"review":"","added":9999292,"hdCover":""},{"id":"09893bb","title":"Вселенная DC. Rebirth. Бэтмен. Книга 6. Свадьба (сборник)","author":"Том Кинг","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003695050/140/987c/Tom_King__Vselennaya_DC._Rebirth._Betmen._Kniga_6._Svadba_sbornik.jpg","isbn":"978-5-389-17631-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Долгие годы Кошка и Мыш сражались друг против друга, а теперь они сражаются бок о бок. И наконец-то могут не скрывать свои истинные чувства… Мало того, Бэтмен с Женщиной-Кошкой даже готовы скрепить эти отношения свадьбой. И хотя самая крутая пара Готэма собирается пожениться тайно, не привлекая внимания врагов, Джокер не намерен с этим мириться.  Пока Брюс и Селина готовятся связать себя узами брака, в Готэме нежданно-негаданно объявляется Бустер Голд, который приносит отнюдь не благие вести. Пространственно-временной континуум вновь трещит по швам, и наводить порядки в альтернативном будущем нужно уже сейчас.  Наконец, все готово к тому, чтобы навсегда перевернуть жизнь двух легендарных героев комиксов. Но готовы ли они сами к подобным переменам?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-03","rating":3.5,"review":"","added":9999291,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893ba","title":"Вселенная DC. Rebirth. Бэтмен. Книга 5. Невеста или воровка? (сборник)","author":"Том Кинг","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003171803/140/ba70/Tom_King__Vselennaya_DC._Rebirth._Betmen._Kniga_5._Nevesta_ili_vorovka_sbornik.jpg","isbn":"978-5-389-16513-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Весь мир услышал это «да».  Предложение, которое Бэтмен сделал Женщине-Кошке, изменило не только их жизнь. Новость о союзе между величайшим в мире детективом и опаснейшей преступницей Готэма взбудоражила каждого, чья судьба когда-либо была связана с Темным Рыцарем: от юных героев, взятых им под опеку, и его друзей из Лиги Справедливости до демонов прошлого.  Прежде чем Бэтмен и Женщина-Кошка скажут друг другу «да» перед алтарем, их ждет серьезная проверка. Они должны будут пересечь пустыню и проникнуть на запретную территорию уединенной крепости, где встретятся с бывшей подружкой Бэтмена, беспощадной Талией аль Гул. Им придется провести в разлуке ни один десяток лет, а также, действуя сообща, помешать Ядовитому Плющу захватить мир. Справятся ли Бэтмен и Женщина-Кошка с выпавшими на их долю испытаниями? Время покажет.  Команда в лице Тома Кинга («Грэйсон», «Вижн»), Джоэль Джонс («Супергерл: Быть супер») и Микеля Ханина («Темная лига справедливости»), а также приглашенные художники Клэй Манн и Ли Уикс представляют книгу «Бэтмен. Книга 5: Невеста или воровка?», которая открывает новую большую главу в жизни Темного Рыцаря и его невесты. В сборник вошли выпуски #33–44, «Бэтмен: Ежегодник» #2, а также оригинальный сценарий комикса «Бэтмен» #44, скетчи Джоэль Джонс и фрагменты комиксов о Бэтмене прежних лет.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-03","rating":4.5,"review":"","added":9999290,"hdCover":""},{"id":"09893b9","title":"Вселенная DC. Rebirth. Бэтмен/Флэш. Значок","author":"Brad Anderson,Джошуа Уильямсон,Говард Портер,Джейсон Фабок,Том Кинг,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002873047/140/016f/__Vselennaya_DC._Rebirth._BetmenFlesh._Znachok.jpg","isbn":"978-5-389-15062-1","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы. Rebirth","genres":["Комиксы","манга","графические романы"],"annotation":"ЕЩЕ ОДНА КЛЮЧЕВАЯ ГЛАВА В ИСТОРИИ ПЕРЕЗАПУЩЕННОЙ ВСЕЛЕННОЙ DC!  Незримые силы каким-то непостижимым образом управляют событиями нашего мира. Единственная подсказка, которую они оставили – это забрызганный кровью загадочный желтый значок. Откуда он взялся? Кто переместил его сюда? Вполне возможно, что значок представляет ценность не только для нашей вселенной, ведь Обратный Флэш готов убить любого, лишь бы завладеть им!  Звездная команда создателей книги «БЭТМЕН / ФЛЭШ: ЗНАЧОК» в лице Джошуа Уильямсона, Тома Кинга, Джейсона Фейбока и Говарда Портера дает ответ на важнейший вопрос, будоражащий умы с момента запуска инициативы REBIRTH – кто наблюдает за Вселенной DC? В сборник вошли выпуски #21-22 «БЭТМЕНА» и #21-22 «ФЛЭША», открывающие дорогу к великому событию под названием «ЧАСЫ СУДНОГО ДНЯ»!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-03","rating":4,"review":"","added":9999289,"hdCover":""},{"id":"09893b8","title":"Земля Икс. Книга 2. №145","author":"Алекс Росс,Джим Крюгер","type":"Книга","cover":"https://s1.livelib.ru/boocover/1004112145/140/9ca1/__Zemlya_Iks._Kniga_2._No145.jpg","isbn":"","publisher":"Ашет Коллекция, Ашетт Коллекция","pubDate":"2019","language":"","series":"Marvel. Официальная коллекция комиксов","genres":[],"annotation":"Продолжение саги об альтернативной реальности, где все жители Земли стали сверхлюдьми, а стары всеми забытые супергерои ведут отчаянную битву за спасение планеты от неминуемой гибели.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-02","rating":3.5,"review":"","added":9999288,"hdCover":""},{"id":"09893b7","title":"Земля Икс. Книга 1. №143","author":"Алекс Росс,Джим Крюгер","type":"Книга","cover":"https://s1.livelib.ru/boocover/1004112142/140/d7c0/__Zemlya_Iks._Kniga_1._No143.jpg","isbn":"","publisher":"Ашет Коллекция, Ашетт Коллекция","pubDate":"2019","language":"","series":"Marvel. Официальная коллекция комиксов","genres":[],"annotation":"В результате загадочного происшествия все жители Земли получают суперспособности. Годы спустя Наблюдатель призывает на Луну Человека-Машину Икс-51, чтобы вести хронику человечества, которое, возможно, в скором времени должно исчезнуть.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-02","rating":3.5,"review":"","added":9999287,"hdCover":""},{"id":"09893b6","title":"Удивительный Человек-Паук. Новые способы умереть. Рождение Анти-Венома","author":"Дэн Слотт,Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002747237/140/1ac6/__Udivitelnyj_ChelovekPauk._Novye_sposoby_umeret._Rozhdenie_AntiVenoma.jpg","isbn":"978-5-91339-581-8","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Ты — достойный, славный и первоклассный герой. Ты спасал город столько раз, что и не сосчитать. Но как до тебя не доходит, Паучок? На каждую спасённую жизнь приходятся миллионы новых способов умереть! Особенно когда Норман Озборн выходит на сцену. Он собирается одолеть тебя, и план его куда хитрее, чем раньше… и плюс к тому — теперь на его стороне закон!  Он и его Громовержцы — худшие из худших, вроде Меченого и Венома — теперь считаются хорошими ребятами! Пройдя через столько ужасных метаморфоз, Эдди Брок теперь страшнее, чем раньше, и он тоже идёт по твоему следу! Вдобавок твой друг Гарри Озборн ведёт себя очень странно — с чего это в последнее время он столь переменчив? — вот и полный комплект проблем — получи и распишись!  Признай, Паучок: возможно, это и Совершенно Новый День… но он может стать и твоим последним!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-02","rating":3,"review":"","added":9999286,"hdCover":""},{"id":"09893b5","title":"Рыцари Marvel. Человек-Паук","author":"Марк Миллар","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003624494/140/1b33/Mark_Millar__Rytsari_Marvel._ChelovekPauk.jpg","isbn":"978-5-04-109367-9","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Человек-Паук. Избранное","genres":["Комиксы","манга","графические романы"],"annotation":"Худший кошмар Питера Паркера стал явью: один из врагов Человека-Паука узнал тайну его личности и собирается использовать её, чтобы напасть на семью Питера. Его любимую тётю Мэй похитили, а жена, Мэри Джейн, может стать следующей. Питер сражается против загадочного врага, который хитростью втянул его в ужасную игру. Теперь Человеку-Пауку придётся столкнуться с дюжиной своих опаснейших врагов, чтобы спасти тётю. Но время бежит! Ждёт ли Человека-Паука великий триумф... или же величайшее поражение?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-02","rating":4,"review":"","added":9999285,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
