  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893b4","title":"Осада","author":"Брайан Майкл Бендис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004814634/140/53d6/Brajan_Majkl_Bendis__Osada.jpg","isbn":"978-5-6043396-1-9","publisher":"Jellyfish Jam","pubDate":"2019","language":"","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Защитники вселенной Marvel уязвимы, как никогда: их расколола гражданская война супергероев, вторжение скруллов посеяло в их рядах паранойю и недоверие, и многие из них находятся в федеральном розыске. Это как раз тот момент, когда злодеи могут нанести самый болезненный удар — и они пользуются моментом. Норман Озборн, заручившись поддержкой Локи, начинает осаду Асгарда, волшебного королевства, которое висит в небе над территорией Америки. Чтобы остановить Озборна и его армию суперзлодеев, нужна армия супергероев — но для этого нужно прекратить распри и забыть паранойю...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-02","rating":4,"review":"","added":9999284,"hdCover":""},{"id":"09893b3","title":"Бэтмен. Белый Рыцарь","author":"Шон Гордон Мёрфи,Мэтт Холлингсворт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003244530/140/3e5a/__Betmen._Belyj_Rytsar.jpg","isbn":"978-5-389-16985-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Действие комикса «БЭТМЕН: БЕЛЫЙ РЫЦАРЬ» разворачивается в мире, где главный клоун-маньяк вселенной DC, терроризировавший Готэм на протяжении многих лет, неожиданно исцеляется от безумия. В центре повествования – ранее Джокер, а ныне Джек Напьер, который собирается во что бы то ни стало избавить любимый город от всевозможных пороков. Воссоединившись со своей подругой Харли Квинн, Напьер приводит в исполнение тщательно продуманный план по дискредитации Бэтмена и возведению себя на пьедестал всенародной любви.  Но грехи прошлого не дадут Напьеру воплотить задуманное в жизнь. Все, чего он добился, начинается рушиться на глазах, как карточный домик. Ведь на место одного Джокера всегда придет другой, и одолеть его можно только проверенными методами.  Популярный сценарист и художник Шон Мерфи в истории «БЭТМЕН: БЕЛЫЙ РЫЦАРЬ» заглядывает в душу величайшего злодея во вселенной DC. В этой невероятной истории собрано восемь выпусков одноименной мини-серии, ставшей дебютом «DC Black Label» – импринта, в котором всемирно известные сценаристы и художники представят ключевых персонажей издательства такими, какими вы никогда их прежде не видели.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-01","rating":4.5,"review":"","added":9999283,"hdCover":""},{"id":"09893b2","title":"Бэтмен. Двор Сов (сборник)","author":"Скотт Снайдер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003244532/140/36dc/Skott_Snajder__Betmen._Dvor_Sov_sbornik.jpg","isbn":"978-5-389-17007-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Двор Сов… Бэтмен слышал о нем. Все слышали, каждый ребенок знает стишок: «Берегитесь: Двор Совиный неустанно следит…» Говорят, Совы – настоящие хозяева Готэма, хоть никто их и не видел. Говорят, они вершат свой суд над неугодными. Говорят, от них не скроешься. Много чего говорят… Темный Рыцарь не верит в эти слухи. Что бы там не болтали, считает он, Готэм – город Бэтмена. Однако вскоре ему предстоит понять, как глубоко он заблуждался.  Мрачные легенды не лгут: Готэмом втайне правят могущественные хищники, и гнезда их повсюду.  Звездный дуэт писателя Скотта Снайдера и художника Грега Капулло с гордостью представляет «Бэтмен. Двор Сов» – грандиозная история о загадках и ужасах Готэма, ставшая одной из самых заметных в комиксах о Темном Рыцаре.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-01","rating":4.5,"review":"","added":9999282,"hdCover":""},{"id":"09893b1","title":"Сорвиголова. Полное издание. Книга 2","author":"Алекс Малеев,Брайан Майкл Бендис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002956027/140/8b5d/__Sorvigolova._Polnoe_izdanie._Kniga_2.jpg","isbn":"978-5-91339-736-2","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"(Фрэнк) Миллер перешел к миру, но Брайан Бендис смог перевоплотиться на новый уровень, не посягая на старую территорию... Проще говоря, ран Бендиса/Малеева на Сорвиголове\" — один из величайших творческих периодов в истории Marvel\". — Рич Джордж, IGN.com  В рамках своего рана, в которой сильно изменился герой, Брайан Майкл Бендис использовал бульварный подход к раскрытию огромного разнообразия персонажей, окружающих людей без страха, и он делал это невероятно тонко и современно. Получив премию, Айснера за лучшую продолжающуюся серию, Бендис и художник Алекс Малеев подарили Сорвиголову славу и включили его в список величайших героев. Теперь этот исторический период собран в трех огромных книгах!  В сборник вошли выпуски комикса \"Сорвиголова\" № 41-50 и № 56-65, написанные Бендисом и нарисованные Малеевым.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-01","rating":4.5,"review":"","added":9999281,"hdCover":""},{"id":"09893b0","title":"Marvel Нуар. Полное издание","author":"Скотт Снайдер,Фред Ван Ленте,Александр Ирвин,Мур Стюарт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003134454/140/6172/__Marvel_Nuar._Polnoe_izdanie.jpg","isbn":"978-5-04-102195-5","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Marvel Нуар","genres":["Комиксы","манга","графические романы"],"annotation":"Встречайте вселенную Marvel в мрачных оттенках! Обласканная критиками и фанатами серия \"Наур\" теперь собрана под одной обложкой и готова стать настоящим украшением любой комикс-коллекции. В сборнике вы найдете истории о Человеке-Пауке, Сорвиголове, Карателе, Железном Человеке, Люке Кейдже, Росомахе и других членах команды \"Люди Икс\".","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-01","rating":3,"review":"","added":9999280,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893af","title":"Сорвиголова. Нуар","author":"Александр Ирвин,Томм Кокер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002054159/140/323d/__Sorvigolova._Nuar.jpg","isbn":"978-5-91339-468-2","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Это один из первых уроков игры в покер, который обычно познаётся на горьком опыте: сыграй в покер с лжецом и будь готов потерять свои деньги, кров и даже душу.  А в городе, в котором правосудие - это игра, слепому Мэтту Мёрдоку совсем скоро предстоит очень хорошо усвоить этот урок. Добро пожаловать в круговорот жестокости, Сорвиголова. Он был здесь до того, как ты родился в этом грязном городе, он будет тут после того, как ты окажешься в могиле. И во время Великой депрессии, охватившей Манхэттен и Адскую Кухню, ты получишь в этом круговороте свою роль. И, дабы сыграть её, ты должен будешь пройти через Кингпина!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-01","rating":3,"review":"","added":9999279,"hdCover":""},{"id":"09893ae","title":"Аннигиляция. Книга третья (сборник)","author":"Кит Гиффен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003281779/140/a0f7/Kit_Giffen__Annigilyatsiya._Kniga_tretya_sbornik.jpg","isbn":"978-5-91878-388-7","publisher":"Фантастика Книжный Клуб","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Аннигиляционная Волна продолжает свой разрушительный марш по галактике, но наталкивается на решительное сопротивление, во главе которого — Нова, а за ним вся мощь его сторонников, таких как Дракс, Ронан и Гамора. Однако в арсенале у Аннигилуса теперь новое оружие: Галактус, Пожиратель Миров! Против такого могущества сопротивление кажется бесполезным. И у горстки бойцов, что всё ещё противостоит Аннигилусу, остается единственная надежда: безумный титан Танос! К несчастью, его старинный враг Дракс, возможно, имеет на этот счёт собственные планы. Спираль войны закручивается, приближаясь к развязке, рушатся цивилизации, приносятся жертвы, и приходит время новых героев! Бурный финал истории «Аннигиляции» подарили сценаристы Кит Гиффен, Кристос Н. Гейдж и Стюарт Мур, а также художники Андреа Дивито, Джузеппе Камунколи, Майк Маккон и Скотт Колинс.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-01","rating":4.5,"review":"","added":9999278,"hdCover":""},{"id":"09893ad","title":"Росомаха MAX","author":"Джейсон Старр","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003454096/140/9d6c/Dzhejson_Starr__Rosomaha_MAX.jpg","isbn":"978-5-04-106961-2","publisher":"Эксмо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В чудовищной авиакатастрофе погибли все пассажиры, кроме одного — Джона Гранта. Чтобы пережить такое, нужна невероятная удача... или поразительный исцеляющий фактор! А он у Джона имеется, судя по отросшим заново ногам. Кто или что он? Джон Грант, Логан, Росомаха, Джон Коллинсворт... Имён много, но какое из них настоящее? Почему он помнит события, произошедшие 150 лет назад? Откуда у него в руках невероятно прочные и острые когти? Кто, чёрт возьми, взорвал самолёт, на котором он летел? У Росомахи целая куча вопросов, и он собирается найти на них ответы! Поиски правды приведут его из Японии в Лос-Анджелес, а оттуда в Лас-Вегас. Ни Виктор Крид, ни Микки Голд, ни банды якудза, ни мексиканские картели не смогут помешать Логану вернуть своё прошлое! Оставляя за собой след из окровавленных трупов, Росомаха получит все ответы!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-01","rating":3.5,"review":"","added":9999277,"hdCover":""},{"id":"09893ac","title":"Аннигиляция. Книга вторая (сборник)","author":"Кит Гиффен,Javier Grillo-Marxuach,Саймон Фурман","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003239265/140/2a4c/__Annigilyatsiya._Kniga_vtoraya_sbornik.jpg","isbn":"978-5-91878-281-1","publisher":"Фантастика Книжный Клуб","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Волна Аннигиляции прочёсывает галактику в поисках бывших вестников Галактуса, и Серебряный Сёрфер вынужден искать былого господина и готовиться к решающей битве с предвечными врагами! Пока Волна обрушивается на территории крии и скруллов, на наших глазах Суперскрулл, сражаясь за жизнь своего сына, готовит удар по Аннигилусу из Негативной Зоны! А Ронан, изгнанный из Обвинителей, пытается вернуть себе доброе имя, но оказывается лицом к лицу с армией могучих воительниц, ведомых Гаморой! Тем временем Танос и Аннигилус заключают союз — но какова их цель?  История Аннигиляции продолжается — благодаря авторам Киту Гиффену, Симону Фурману и Хавьеру Грильо-Марксуа и художникам Ренато Арлему, Хорхе Перейра Лукасу и Грегори Титусу","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-12","rating":4,"review":"","added":9999276,"hdCover":""},{"id":"09893ab","title":"Сорвиголова. Полное издание. Книга 1","author":"Алекс Малеев,Брайан Майкл Бендис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002414548/140/384b/__Sorvigolova._Polnoe_izdanie._Kniga_1.jpg","isbn":"978-5-91339-524-5","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В рамках своего рана, который определил характер персонажа, Брайан Майкл Бендис, используя бульварный стиль повествования с гибким и современным подходом, показал всё богатое разнообразие персонажей и психологических драм.  Автор данной серии, Брайан Бендис и художник Алекс Малеев, получили премию Айснера «За лучшую серию», ведь они вернули персонажа в ряд лучших, где ему и место. И весь этот исторически важный период собран в трёх огромных сборниках, первый из которых вы держите в руках!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-12","rating":5,"review":"","added":9999275,"hdCover":""},{"id":"09893aa","title":"Халк #181. Первое появление Росомахи","author":"Лен Уэйн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004681377/140/2a99/Len_Uejn__Halk_181._Pervoe_poyavlenie_Rosomahi.jpg","isbn":"978-5-04-108278-9","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Классика Marvel","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-12","rating":3.5,"review":"","added":9999274,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
