SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893a9","title":"Человек-Паук. Том 2. Новый день","author":"Дэн Слотт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003354021/140/28cc/Den_Slott__ChelovekPauk._Tom_2._Novyj_den.jpg","isbn":"978-5-04-107537-8","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Охотница Крэйвен устраивает на Паучка свою первую охоту, и герою нужно как-то её пережить. Да, это не тот Кравинов, о котором вы подумали. Возможно, она даже опаснее! Затем Паучок столкнётся с Норманом Озборном, который тоже изменился… потому что теперь на его стороне закон. И тёмная версия правопорядка Озборна поддерживается безумными Громовержцами! Ещё один классический злодей Паучка, Кувалда, был воскрешён одним из новых врагов Паучка, нигилистическим мистером Негативом. И вместе они творят преступные дела… но раз летят пули, куда же без Карателя! Плюс: Джекпот сталкивается с Секретным вторжением Скруллов!  В книгу входят комиксы \"Удивительный Человек-Паук\" (1963) #565–567, ежегодник \"Удивительного Человека-Паука\" (2008) #1, \"Секретное вторжение: Удивительный Человек-Паук\" #1–3 и материалы из \"Удивительного Человека-Паука. Экстра!\" #1. Над комиксом работали Марк Гуггенхайм, Дэн Слотт, Марк Уэйд, Джо Келли, Зеб Уэллс, Брайан Рид, Фил Хименез, Джон Ромита – мл., Ади Гранов, Барри Китсон, Крис Бачало, Паоло Ривера, Майк Маккоун, Марко Сантуччи и Пэт Олифф.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-12","rating":4,"review":"","added":9999273,"hdCover":""},{"id":"09893a8","title":"Удивительный Человек-Паук #129. Первое появление Карателя","author":"Джерри Конвей","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003640296/140/87f0/Dzherri_Konvej__Udivitelnyj_ChelovekPauk_129._Pervoe_poyavlenie_Karatelya.jpg","isbn":"978-5-04-108287-1","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Классика Marvel","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-12","rating":3.5,"review":"","added":9999272,"hdCover":""},{"id":"09893a7","title":"Классика Marvel. Фантастическая Четвёрка","author":"Стэн Ли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002995915/140/3115/Sten_Li__Klassika_Marvel._Fantasticheskaya_Chetvjorka.jpg","isbn":"978-5-04-102193-1","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Первые десять выпусков Фантастической Четвёрки под одной обложкой! Стэн Ли! Джек Кирби! Рид Ричардс! Бен Гримм! Сью Шторм! Джонни Шторм! Круто? Не то слово! В качестве оппонентов легендарной команды выступят легендарные Человек-Крот, Скруллы, Кукловод, Нэмор, Чудотворец и сам Доктор Дум! Рид Ричардс превратится в колесо! Существо станет пиратом! Монстры очень удивятся этим событиям!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-12","rating":4,"review":"","added":9999271,"hdCover":""},{"id":"09893a6","title":"Нелюди","author":"Пол Дженкинс,Джей Ли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002870813/140/e8c8/__Nelyudi.jpg","isbn":"978-5-91878-283-5","publisher":"Фантастика Книжный Клуб","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"«Нелюди» — одна из самых продолжительных нестандартных серий Marvel. Речь идёт о расе генетически аномальных индивидов, изолированно живущих в островном королевстве Аттилан. Они сами подвергают себя мутациям: в ходе ритуала взросления каждый нелюдь контактирует с терригенным туманом, придающим ему необыкновенные способности, какие-то из них замечательны, другие — ужасающи. Сейчас Аттилан стал жертвой нападения как извне, так и изнутри. Сможет ли королевская семья во главе с безмолвным Чёрным Громом отразить натиск иноземных захватчиков, атаковавших защитный периметр, и справиться с внутренней угрозой в лице сумасшедшего брата Чёрного Грома — Максимуса Безумного? Пол Дженкинс и Джей Ли вплетают в историю одной из старейших семей Marvel современные проблемы, включая международную политику, классовую борьбу и вечные трудности взросления. Этот мрачноватый и захватывающий комикс остаётся в числе самых популярных в серии «Рыцари Marvel»","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-12","rating":3.5,"review":"","added":9999270,"hdCover":""},{"id":"09893a5","title":"Аннигиляция. Книга первая (сборник)","author":"Кит Гиффен,Дэн Абнетт,Энди Лэннинг","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003160437/140/bf81/__Annigilyatsiya._Kniga_pervaya_sbornik.jpg","isbn":"978-5-91878-280-4","publisher":"Фантастика Книжный Клуб","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Аннигиляционная Волна пришла! Аннигилус, повелитель Негативной Зоны, объявил войну! Орды его верных солдат кишат в самом сердце Вселенной, и только горстка героев может спасти её от разрушения! Корпусу Нова на Ксандаре пришёл конец, выжил только Ричард Райдер — человек, которого теперь называют Нова. Отныне он единственный хранитель Мирового Разума — ксандарианской базы данных опыта и знаний, но сможет ли он обрести себя и возглавить борьбу с Аннигиляционной Волной? Дракс Разрушитель возвращается из своего изгнания на Земле, чтобы наставлять Нову, но вы ещё увидите, насколько опасна его новая личность! Приглашённые звёзды — Квазар, Ронан Обвинитель, Серебряный Сёрфер и Танос! Аннигиляция начинается. Благодарности авторам: Киту Гиффену, Дэну Абнетту и Энди Лэннингу. а также художникам: Митчу Брайтвайзеру, Скотту Колинзу, Ариэлю Оливетти и Кевину Уокеру.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-12","rating":4,"review":"","added":9999269,"hdCover":""},{"id":"09893a4","title":"Фантастическая Четвёрка. Решить Всё","author":"Джонатан Хикман","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003558955/140/76eb/Dzhonatan_Hikman__Fantasticheskaya_Chetvjorka._Reshit_Vsjo.jpg","isbn":"978-5-6042815-7-4","publisher":"Параллель Комикс","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"«Фантастическая Четвёрка: Решить Все» — это интеллектуальная смесь из семейной супергероики и научной фантастики от одного из главных архитекторов вселенной Marvel, великого и ужасного Джонатана Хикмана. «Величайший комикс на свете», повествующий о столкновении ФЧ с беспощадным Норманом Озборном, а также роковом открытии в жизни Рида Ричардса, которому суждено изменить не только мир Фантастической Четверки, но и всю мультивселенную.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-11","rating":4.5,"review":"","added":9999268,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893a3","title":"Тор. Латверианский Прометей","author":"Кирон Гиллен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002993219/140/c79b/Kiron_Gillen__Tor._Latverianskij_Prometej.jpg","isbn":"978-5-91878-322-1","publisher":"Фантастика Книжный Клуб","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Чудовищным зверствам подверг доктор Дум асгардцев, поселившихся в королевстве Латверия. И теперь король Бальдр собирает войско и обращается за советом к своему генералу — Тюру, богу войны. Даже изгнанника Тора призвали на защиту его народа. Но что за секретное оружие создал Дум, похитив тайны Асгарда? И на чьей же на самом деле стороне двуличный Локи? А также… Претерпев мучения от рук Локи, богиня Сиф вместе с Бета Рэй Биллом пускается в путь, чтобы в битвах вернуть себе истинную воинскую доблесть! И вдобавок — абсолютно новая история от Стэна Ли в честь грандиозного празднования по случаю юбилейного выпуска Могучего Marvel.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-11","rating":4,"review":"","added":9999267,"hdCover":""},{"id":"09893a2","title":"Хоукай - Соколиный глаз. Полное издание","author":"Мэтт Фрэкшн, Дэвид Аха","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002593567/140/0b72/Mett_Frekshn_Devid_Aha__Houkaj__Sokolinyj_glaz._Polnoe_izdanie.jpg","isbn":"978-5-91339-523-8","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"Герои Marvel","genres":["Комиксы","манга","графические романы"],"annotation":"Клинт Бартон, бывалый профи. Кейт Бишоп, талантливый новичок. Два Хоукая зависают вместе, обмениваются стрелами, прикрывают тыл друг друга. Но не так, как вы подумали. Просто два лучных друга, никакой романтики. Никаких натянутых улыбок, господа. Лишь натянутая тетива. Клинту хватает проблем с бывшей девушкой, женой, текущей «подружкой» и рыжей дамочкой с машиной его мечты. Не говоря о недавно купленном им здании, армии упырей в трениках, которые хотят его вернуть, и невероятной собаке, чующей за версту и убийства, и пиццу. А ещё тут Мадам Маска, клоун-убийца и нищеброд-брательник Клинта, Барни. С таким набором битва Мстителей против Таноса покажется невинным пикником. Чаша терпения Кейт переполняется, и она уезжает. Говорят, Лос-Анджелес в это время года просто сказка. Но что об этом думает пёс? И кстати, вы когда-нибудь представляли, как может выглядеть комикс на языке жестов?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-11","rating":4,"review":"","added":9999266,"hdCover":""},{"id":"09893a1","title":"Росомаха. Враг государства (сборник)","author":"Марк Миллар,Джон Ромита-ст.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003547994/140/fcb8/__Rosomaha._Vrag_gosudarstva_sbornik.jpg","isbn":"978-5-04-106956-8","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Ниндзя Руки промыли Росомахе мозги, поэтому теперь он кромсает и друзей, и врагов, убив в результате одного из Иксов! Росомаху ловят, депрограммируют и отправляют биться с бывшими хозяевами, но в царстве смерти и разрушения даже самый яростный мутант на Земле может не справиться со смертоносным взглядом Горгона.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-11","rating":4,"review":"","added":9999265,"hdCover":""},{"id":"09893a0","title":"Миротворцы. Выпуск 2","author":"Даниил Ветлужских","type":"Книга","cover":"https://s1.livelib.ru/boocover/1004021299/140/2af2/Daniil_Vetluzhskih__Mirotvortsy._Vypusk_2.jpg","isbn":"978-5-6042733-2-6","publisher":"MOLOT HardCorp","pubDate":"2019","language":"Русский","series":"Миротворцы","genres":[],"annotation":"Миротворцы - разношёрстные неудачники, которых собрали в команду для распила госбюджета во благо ушлых чиновников. Общественность считает их героями. Чиновники считают их отличным инструментом.  Кастинг в команду успешно пройден! Миротворцы готовы показать себя всей России! Но всё ли пройдёт успешно? Всё ли пойдёт по плану?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-10","rating":4,"review":"","added":9999264,"hdCover":""},{"id":"098939f","title":"Человек-Паук. Новый день. Том 1","author":"Зеб Уэллс,Боб Гейл,Дэн Слотт,Марк Макнивен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003248550/140/e25f/__ChelovekPauk._Novyj_den._Tom_1.jpg","isbn":"978-5-04-105990-3","publisher":"Комильфо","pubDate":"2019","language":"","series":"Человек-Паук. Избранное","genres":["Комиксы","манга","графические романы"],"annotation":"После событий \"Ещё одного дня\" жизнь Питера Паркера перевенулась с ног на голову, но он решил оставить прошлое позади и уверенно пойти навстречу \"Новому дню\". Такой смены статус-кво вы ещё не видели: тут есть новые враги и новые друзья, но без знакомых лиц тоже не обошлось. Теперь жизнь Питера безумнее некуда! Мало того что в \"Дэйли Бьюгл\" произошли большие изменения, на дворе бушует ураган, а по улицам слоняется стример Чудила, так ещё и громящий всё и вся Урод вынуждает Питера обратиться к своим товарищам Мстителям. Признай, тигрёнок, это Джекпот! А также: кто победит в битве стенолаза и паутиноплёта, когда в городе объявится таинственный другой Человек-Паук?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-10","rating":4,"review":"","added":9999263,"hdCover":""},{"id":"098939e","title":"Ultimate X-Men: Ultimate Collection Book 1","author":"Марк Миллар,Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000297882/140/5b1a/__Ultimate_XMen_Ultimate_Collection_Book_1.jpg","isbn":"0785121870","publisher":"Marvel Comics","pubDate":"2006","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Collecting the first year of Mark Millar''s groundbreaking ULTIMATE X-MEN - issues #1-12 - in one colossal trade paperback! Featuring an all-new cover by ULTIMATE HULK VS. WOLVERINE artist Leinil Francis Yu! The world stands on the brink of genetic war. Mankind has made the first move, launching an army of giant, cybernetic executioners called Sentinels - programmed to target and eliminate the mutant DNA strand. Now, Magneto and his mutant terrorist cell are preparing to follow through on their threats of Homo sapien genocide. The only force that can prevent total annihilation: five awkward teenagers and their crippled mentor! Plus: The inexperienced X-Men must rely on the enigmatic and unproven Wolverine when they become pawns of the mysterious Weapon X program. Can Logan go it alone against the shadow-ops organization that transformed him into one of the world''s most lethal killing machines? Also featuring the rare ULTIMATE X-MEN #1/2!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-08","rating":4.5,"review":"","added":9999262,"hdCover":""}]');
